<?php
namespace App\Controllers;
use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class PublicEstimateController{
 public function show(string $token):void{$pdo=Database::connection();$s=$pdo->prepare('SELECT e.*,c.display_name,c.email,p.address1,p.city,p.state,p.postal_code FROM estimates e JOIN customers c ON c.id=e.customer_id LEFT JOIN properties p ON p.id=e.property_id WHERE e.public_token=?');$s->execute([$token]);$estimate=$s->fetch();if(!$estimate){http_response_code(404);exit('Estimate not found');}$i=$pdo->prepare('SELECT * FROM estimate_items WHERE estimate_id=?');$i->execute([$estimate['id']]);View::render('public/estimate',['title'=>'Estimate '.$estimate['estimate_number'],'estimate'=>$estimate,'items'=>$i->fetchAll()],'public');}
 public function accept(string $token):void{verify_csrf();$pdo=Database::connection();$pdo->beginTransaction();try{$s=$pdo->prepare('SELECT * FROM estimates WHERE public_token=? FOR UPDATE');$s->execute([$token]);$e=$s->fetch();if(!$e)throw new \RuntimeException('Estimate not found.');if($e['status']==='accepted'){flash('info','This estimate was already accepted.');$pdo->rollBack();redirect('/estimate/'.$token);} $pdo->prepare("UPDATE estimates SET status='accepted',accepted_at=NOW() WHERE id=?")->execute([$e['id']]);$num=next_number('JOB-');$pdo->prepare('INSERT INTO jobs(job_number,customer_id,property_id,estimate_id,service_summary,status,notes) VALUES(?,?,?,?,?,?,?)')->execute([$num,$e['customer_id'],$e['property_id'],$e['id'],'Services from '.$e['estimate_number'],'unscheduled',$e['notes']]);$jobId=(int)$pdo->lastInsertId();$pdo->commit();AuditService::log('estimate.public_accepted','estimate',(int)$e['id'],['job_id'=>$jobId]);flash('success','Thank you. Your estimate has been accepted and we will contact you to schedule service.');redirect('/estimate/'.$token);}catch(\Throwable $x){$pdo->rollBack();flash('danger',$x->getMessage());redirect('/estimate/'.$token);}}
 public function decline(string $token):void{verify_csrf();$s=Database::connection()->prepare("UPDATE estimates SET status='declined',declined_at=NOW() WHERE public_token=? AND status<>'accepted'");$s->execute([$token]);flash('info','The estimate has been declined.');redirect('/estimate/'.$token);}
}
